Функция ПолучитьСуммарныйДолгКонтрагента(Контрагент) Экспорт
    Если ПустаяСтрока(Контрагент) Тогда
        Возврат 0;
    КонецЕсли;

    Запрос = Новый Запрос;
    Запрос.Текст = "ВЫБРАТЬ
    |    Взаиморасчеты.Остатки.СуммаОстаток
    |ИЗ
    |    РегистрНакопления.Взаиморасчеты.Остатки(&Контрагент) КАК Взаиморасчеты
    |ГДЕ
    |    Взаиморасчеты.Договор.Владелец = &Контрагент
    |    И Взаиморасчеты.СуммаОстаток > 0";
    Запрос.УстановитьПараметр("Контрагент", Контрагент);

    Результат = Запрос.Выполнить();
    Выборка = Результат.Выбрать();
    СуммаДолга = 0;
    Пока Выборка.Следующий() Цикл
        СуммаДолга = СуммаДолга + Выборка.СуммаОстаток;
    КонецЦикла;

    Возврат СуммаДолга;
КонецФункции
